 1	import * as React from 'react';
 2	import classNames from 'classnames';
 3	import { Tooltip } from '@patternfly/react-core';
 4	import { GlobeAmericasIcon } from '@patternfly/react-icons';
 5	import * as dateTime from './datetime';
 6	
 7	const timestampFor = (
 8	  mdate: Date,
 9	  now: Date,
10	  omitSuffix: boolean,
11	  simple?: boolean,
12	  ignoreRelativeTime?: boolean
13	) => {
14	  if (!dateTime.isValid(mdate)) {
15	    return '-';
16	  }
17	
18	  const timeDifference = now.getTime() - mdate.getTime();
19	  if (omitSuffix || simple) {
20	    return dateTime.fromNow(mdate, undefined, { omitSuffix });
21	  }
22	
23	  // Show a relative time if within 10.5 minutes in the past from the current time.
24	  if (
25	    timeDifference > dateTime.maxClockSkewMS &&
26	    timeDifference < 630000 &&
27	    !ignoreRelativeTime
28	  ) {
29	    return dateTime.fromNow(mdate);
30	  }
31	
32	  // Apr 23, 2021, 4:33 PM
33	  return dateTime.dateTimeFormatter.format(mdate);
34	};
35	
36	export const Timestamp = (props: TimestampProps) => {
37	  // Check for null. If props.timestamp is null, it returns incorrect date and time of Wed Dec 31 1969 19:00:00 GMT-0500 (Eastern Standard Time)
38	  const now = Date.now();
39	  if (!props.timestamp) {
40	    return <div className="co-timestamp">-</div>;
41	  }
42	
43	  const mdate = props.isUnix
44	    ? new Date((props.timestamp as number) * 1000)
45	    : new Date(props.timestamp);
46	
47	  const timestamp = timestampFor(
48	    mdate,
49	    new Date(now),
50	    props.omitSuffix,
51	    props.simple,
52	    props?.ignoreRelativeTime
53	  );
54	
55	  if (!dateTime.isValid(mdate)) {
56	    return <div className="co-timestamp">-</div>;
57	  }
58	
59	  if (props.simple) {
60	    return <>{timestamp}</>;
61	  }
62	
63	  return (
64	    <div
65	      className={classNames('co-timestamp co-icon-and-text', props.className)}
66	    >
67	      <GlobeAmericasIcon className="co-icon-and-text__icon" />
68	      <Tooltip
69	        content={[
70	          <span className="co-nowrap" key="co-timestamp">
71	            {dateTime.utcDateTimeFormatter.format(mdate)}
72	          </span>,
73	        ]}
74	      >
75	        <span data-test="timestamp">{timestamp}</span>
76	      </Tooltip>
77	    </div>
78	  );
79	};
80	
81	export type TimestampProps = {
82	  timestamp: string | number;
83	  isUnix?: boolean;
84	  simple?: boolean;
85	  omitSuffix?: boolean;
86	  className?: string;
87	  // Simple / omitSuffix can overrride this field
88	  ignoreRelativeTime?: boolean;
89	};
90	
91	Timestamp.displayName = 'Timestamp';

